from kafka import KafkaConsumer
import json

# Define a dictionary to hold message handlers
message_handlers = {}

def register_handler(topic, handler):
    if topic not in message_handlers:
        message_handlers[topic] = []
    message_handlers[topic].append(handler)

def handle_message(message):
    topic = message.topic
    value = json.loads(message.value)
    
    if topic in message_handlers:
        for handler in message_handlers[topic]:
            handler(value)

# Example message handlers
def process_credit_card_transaction(transaction):
    print(f"Processing credit card transaction: {transaction}")

def process_debit_card_transaction(transaction):
    print(f"Processing debit card transaction: {transaction}")

register_handler('credit-card-transactions', process_credit_card_transaction)
register_handler('debit-card-transactions', process_debit_card_transaction)

# Kafka consumer setup
consumer = KafkaConsumer(
    'credit-card-transactions',
    'debit-card-transactions',
    bootstrap_servers=['localhost:9092'],
    auto_offset_reset='earliest',
    enable_auto_commit=True,
    group_id='financial-transaction-consumer-group'
)

for message in consumer:
    handle_message(message)